<section class="v4-page-shell"><div class="v4-page-head"><h1>System Health Dashboard</h1><p>فحص البيئة، التخزين، duplicate media، والروابط الداخلية المكسورة.</p></div>
<div class="v4-kpi-strip"><div class="v4-kpi-card"><strong><?= (int)($report['summary']['trash_files'] ?? 0) ?></strong><span>ملفات داخل trash</span></div><div class="v4-kpi-card"><strong><?= (int)($report['summary']['log_files'] ?? 0) ?></strong><span>تقارير محفوظة</span></div><div class="v4-kpi-card"><strong><?= count($duplicates ?? []) ?></strong><span>مجموعات مكررة</span></div></div>
<section class="v4-seo-card"><h2>Health Checks</h2><ul class="v4-check-list"><?php foreach (($report['checks'] ?? []) as $check): ?><li class="v4-check-<?= e($check['status'] ?? 'warn') ?>"><strong><?= e($check['label'] ?? '') ?>:</strong> <?= e($check['message'] ?? '') ?></li><?php endforeach; ?></ul></section>
<section class="v4-seo-card"><h2>Duplicate Media Detector</h2><?php if (!empty($duplicates)): ?><div class="v4-table-wrap"><table class="v4-table"><thead><tr><th>Hash</th><th>عدد الملفات</th><th>المسارات</th></tr></thead><tbody><?php foreach ($duplicates as $group): ?><tr><td><code><?= e(substr((string)($group['hash'] ?? ''), 0, 12)) ?></code></td><td><?= (int)($group['count'] ?? 0) ?></td><td><?php foreach (($group['items'] ?? []) as $item): ?><div><code><?= e($item['path'] ?? '') ?></code></div><?php endforeach; ?></td></tr><?php endforeach; ?></tbody></table></div><?php else: ?><div class="v4-empty-state"><p>لم يتم اكتشاف ملفات وسائط مكررة ضمن الفحص الحالي.</p></div><?php endif; ?></section>
<section class="v4-seo-card"><h2>Broken Internal Links</h2><?php if (!empty($brokenLinks)): ?><div class="v4-table-wrap"><table class="v4-table"><thead><tr><th>النوع</th><th>العنوان</th><th>الرابط المكسور</th><th>المصدر</th></tr></thead><tbody><?php foreach ($brokenLinks as $row): ?><tr><td><?= e($row['type'] ?? '') ?></td><td><?= e($row['title'] ?? '') ?></td><td><code><?= e($row['url'] ?? '') ?></code></td><td><?php if (!empty($row['source'])): ?><a href="<?= e($row['source']) ?>" target="_blank" rel="noopener">فتح المصدر</a><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div><?php else: ?><div class="v4-empty-state"><p>لم يتم اكتشاف روابط داخلية مكسورة ضمن العيّنة الحالية.</p></div><?php endif; ?></section></section>
